#include <iostream>

class DynString
{
    char* m_data{};
    int m_size{};

public:
    DynString(int size)
        : m_data{ new char[size]{} }, m_size{ size }
    {
    }

    ~DynString()
    {
        delete[] m_data;
        std::cout << "Destroyed " << m_size << " chars\n";
    }

    void set(int index, char c)
    {
        m_data[index] = c;
    }

    void print() const
    {
        for (int i{ 0 }; i < m_size; ++i)
            std::cout << m_data[i];
    }
};

int main()
{
    int n{};
    std::cin >> n;

    DynString ds(n);

    for (int i{ 0 }; i < n; ++i)
    {
        char c{};
        std::cin >> c;
        ds.set(i, c);
    }

    std::cout << "Stored: ";
    ds.print();
    std::cout << '\n';

    return 0;
}

