#include <iostream>

class IntPool
{
    char m_label{};
    int* m_data{};
    int m_size{};

public:
    IntPool(char label, int size)
        : m_label{ label }, m_data{ new int[size]{} }, m_size{ size }
    {
        std::cout << "Created pool '" << m_label << "' (" << m_size << " ints)\n";
    }

    ~IntPool()
    {
        delete[] m_data;
        std::cout << "Destroyed pool '" << m_label << "' (" << m_size << " ints)\n";
    }
};

int main()
{
    int sA{}, sB{}, sC{};
    std::cin >> sA >> sB >> sC;

    IntPool a('A', sA);
    IntPool b('B', sB);
    IntPool c('C', sC);

    return 0;
}
